import{_ as r,o as t,c as n,j as e,a as p,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"灵能","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/5.能量池/灵能.md","filePath":"4.资源分区/5.能量池/灵能.md"}'),o={name:"4.资源分区/5.能量池/灵能.md"};function d(l,a,i,_,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"灵能",tabindex:"-1"},[p("灵能 "),e("a",{class:"header-anchor",href:"#灵能","aria-label":'Permalink to "灵能"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"汹涌疾风027")])])],-1),s('<h1 id="灵能-1" tabindex="-1">灵能 <a class="header-anchor" href="#灵能-1" aria-label="Permalink to &quot;灵能&quot;">​</a></h1><p>灵能</p><p>灵能是一个通用能量池，具有灵能的单位通称为灵能者。灵能代表着一种以自身意志来影响现实的能量，可能表现出物理、能量、时间等不同概念的影响方式。</p><p>灵能的关键属性为：决心+沉着/感知</p><p>灵能的恢复方式：<br> 1、经过长休息后完全恢复<br> 2、进行一次短休息后，恢复等同决心点灵能</p><p>当你具有灵能能量池后，可购买以下强化：</p><p>灵能力成长<br> 价格：D+500<br> 描述：你的灵能与日俱增，变得更为强大。<br> 从现在开始，每场影片中，只要你消耗了灵能力池，那么在这场影片结束之后，你的灵能力池的上限扩大6点，这个效果最多获得3次。当获得2次效果后，你可以每经过一小时，就进行一次灵能力能量池关键属性的判定，恢复成功数点的能量，这个恢复也会计入每日的恢复上限。当你获得全部三次效果之后，你耗费灵能进行的攻击还会额外具有【法破】特性。</p><p>灵能力精炼<br> 价格：C+1000<br> 描述：如果说，你先前的灵能力只是游散的气体，那么你现在就通过自己不断的使用，将原本随意飘浮的灵能变成了凝实的溪流。<br> 从现在开始，一回合一次，你使用灵能力池时，可以将能量的消耗减少传奇决心*2+1点，最低不能低于1，如果你还有减少能量消耗的点数没有使用完，则可以将剩余的减少消耗点数等额转化为在这一轮中，消耗了灵能力进行的决心检定上的能量加值，这个加值的上限为传奇决心*2点。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
